// Get all input items
const items = $input.all();

// Helper to find an item by property presence
function findItem(prop) {
  for (const item of items) {
    if (item.json[prop] !== undefined) return item.json;
  }
  return null;
}

// Extract Trello lists (objects with 'name' and 'closed', no 'fullName')
const lists = items.filter(i => i.json.name && typeof i.json.closed === 'boolean').map(i => i.json);

// Extract Trello members (objects with 'fullName')
const members = items.filter(i => i.json.fullName).map(i => i.json);

// Extract profile (object with 'id' and 'assigned_effort_points')
const profileItem = findItem('assigned_effort_points');
const profiles = profileItem ? [profileItem] : [];

// Extract meeting minutes (from item with 'meeting_minutes')
const minutesItem = findItem('meeting_minutes');
const minutes = minutesItem ? minutesItem.meeting_minutes : null;

// Extract project name (from item with 'project_name')
const projectNameItem = findItem('project_name');
const projectName = projectNameItem ? projectNameItem.project_name : 'Unknown Project';

if (!minutes) throw new Error('No meeting_minutes found in input');

// Build list names for the prompt
const listNames = lists.map(l => l.name.toLowerCase()).filter(n => n === 'backlog' || n.startsWith('sprint'));

// Prepare team info from profile(s)
const teamInfo = profiles.map(p => ({
  id: p.id,
  name: p.name,
  email: p.email,
  role: p.role,
  skills: p.skills || [],
  experience_years: p.experience_years,
  current_effort: p.assigned_effort_points || 0
}));

const project = { name: projectName };

const prompt = `You are an expert Scrum Master and project planner. Extract user stories from the meeting minutes below.

Meeting minutes:
${minutes}

Project: ${project.name}

Available team members (with skills and current workload):
${JSON.stringify(teamInfo, null, 2)}

Trello lists available: ${listNames.join(', ')} (Backlog is default; use Sprint1, Sprint2, etc. for sprint numbers).

For each user story explicitly mentioned or implied in the minutes, produce a JSON object with the following fields:
{
  "id": "US-XXX" (incrementing number),
  "title": "short title",
  "role": "who benefits",
  "goal": "what they want to achieve",
  "benefit": "why it matters",
  "acceptance_criteria": ["list of criteria"],
  "priority": "High/Medium/Low",
  "estimate": number of days (1-10),
  "dependencies": ["other story IDs or external dependencies"],
  "tags": ["dev", "backend", "frontend", "design", "qa", etc.],
  "sprint": null or a sprint number (1,2,3...) matching an available sprint list,
  "assigned": [
    {
      "person_id": integer (from team member id),
      "name": string,
      "email": string,
      "effort": integer (1-10 per person, total effort across assignees should roughly match estimate)
    }
  ]
}

Assignment rules:
- Distribute stories to team members based on their skills, role, and current effort (lower current_effort is better).
- Prefer matching skills (e.g., "backend" for API, "frontend" for UI, "dev" for general coding).
- If a story has multiple skill requirements, assign multiple people.
- Total effort (sum of effort values across assignees) should be close to the story's estimate.
- Use the team members provided; do not invent new names.
- Try to balance workload across the team.

Return ONLY valid JSON with a top-level object: { "stories": [ ... ] }
No markdown, no explanation.`;

// Build listMap for downstream mapping (list name -> Trello list ID)
const listMap = {};
lists.forEach(l => { listMap[l.name.toLowerCase()] = l.id; });

return [{
  json: {
    prompt,
    listMap,
    project,
    profiles,
    bodyForOllama: {
      model: "gpt-oss:120b",
      prompt,
      format: "json",
      stream: false
    }
  }
}];

// Get the first input item (the LLM response)
const llmOutput = $input.first().json;

// Extract the raw response text
let rawResponse = '';

if (llmOutput.response) {
  rawResponse = llmOutput.response;
} else if (llmOutput.text) {
  rawResponse = llmOutput.text;
} else if (llmOutput.content) {
  rawResponse = llmOutput.content;
} else if (typeof llmOutput === 'string') {
  rawResponse = llmOutput;
} else if (Array.isArray(llmOutput) && llmOutput[0]?.response) {
  rawResponse = llmOutput[0].response;
} else {
  throw new Error('Could not find response text in LLM output. Structure: ' + JSON.stringify(llmOutput));
}

// Clean up markdown fences if present
let cleaned = rawResponse.trim();
if (cleaned.startsWith('```json')) {
  cleaned = cleaned.replace(/^```json\s*\n?/, '').replace(/\n?```$/, '');
} else if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```\s*\n?/, '').replace(/\n?```$/, '');
}

// Parse the JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error(`Failed to parse LLM response as JSON: ${err.message}\nRaw text: ${cleaned.substring(0, 500)}`);
}

// Extract the stories array (handles both { stories: [...] } and direct array)
let stories = [];
if (Array.isArray(parsed)) {
  stories = parsed;
} else if (parsed.stories && Array.isArray(parsed.stories)) {
  stories = parsed.stories;
} else if (Array.isArray(parsed.story)) {
  stories = parsed.story;
} else if (parsed.id && parsed.title) {
  // Single story object
  stories = [parsed];
} else {
  throw new Error('LLM response does not contain a stories array. Response: ' + JSON.stringify(parsed));
}

console.log(`Extracted ${stories.length} stories`);

// Try to get listMap and project from the "Create Prompt" node if available and connected
let listMap = {};
let project = { name: 'Unknown' };
try {
  const createPromptNode = $node['Create Prompt'];
  if (createPromptNode && createPromptNode.json) {
    listMap = createPromptNode.json.listMap || {};
    project = createPromptNode.json.project || { name: 'Unknown' };
  }
} catch (e) {
  // Node not accessible, ignore
  console.warn('Could not access Create Prompt node, listMap and project will be empty');
}

return [{
  json: {
    stories: stories,
    listMap: listMap,
    project: project
  }
}];

// Get the input data (stories, listMap, project)
const inputData = $input.first().json;
const stories = inputData.stories || [];
const listMap = inputData.listMap || {};

// Get Trello members from the "Trello Members" node (if connected)
let trelloMembers = [];
try {
  const membersNode = $node['Trello Members'];
  if (membersNode && Array.isArray(membersNode.json)) {
    trelloMembers = membersNode.json;
  } else if (membersNode && membersNode.json) {
    trelloMembers = [membersNode.json];
  } else {
    // Try to get from $items if available
    const membersItems = $('Trello Members').all();
    if (membersItems.length) {
      trelloMembers = membersItems.map(i => i.json);
    }
  }
} catch (e) {
  console.warn('Could not access Trello Members node, member mapping will be skipped.');
}

// Build name-to-Trello-ID mapping
const nameToTrelloId = {};
if (trelloMembers.length) {
  trelloMembers.forEach(member => {
    if (member.fullName) nameToTrelloId[member.fullName] = member.id;
    if (member.username) nameToTrelloId[member.username] = member.id;
    if (member.email) nameToTrelloId[member.email] = member.id;
  });
  console.log(`Loaded ${Object.keys(nameToTrelloId).length} member mappings`);
}

// Map each story to its list ID and member IDs
const mappedStories = stories.map(story => {
  let listId = null;

  // Determine list based on sprint number
  if (story.sprint && story.sprint > 0) {
    // Try variations: "sprint 1", "sprint1", "sprint 01", etc.
    const sprintKey1 = `sprint ${story.sprint}`.toLowerCase();
    const sprintKey2 = `sprint${story.sprint}`.toLowerCase();
    const sprintKey3 = `sprint ${story.sprint.toString().padStart(2, '0')}`.toLowerCase();
    listId = listMap[sprintKey1] || listMap[sprintKey2] || listMap[sprintKey3];
  }

  // Fallback to Backlog list if not found
  if (!listId) {
    listId = listMap['backlog'] || Object.values(listMap)[0];
    if (!listId) console.warn(`No list found for story ${story.id}, using fallback`);
  }

  // Map assigned team members to Trello member IDs
  const assigneeIds = (story.assigned || []).map(assignee => {
    // Try to match by name first, then email
    return nameToTrelloId[assignee.name] || nameToTrelloId[assignee.email] || null;
  }).filter(Boolean);

  if (assigneeIds.length === 0 && story.assigned && story.assigned.length) {
    console.warn(`Could not map assignees for story ${story.id}: ${JSON.stringify(story.assigned)}`);
  }

  return {
    json: {
      ...story,
      listId: listId,
      assigneeIds: assigneeIds
    }
  };
});

return mappedStories;

// Get the mapped stories from the previous node
const items = $input.all();

// Format each story into a Trello card
const formattedCards = items.map((item, index) => {
  const story = item.json;

  // Calculate due date: today + estimate days
  const dueDate = new Date();
  dueDate.setDate(dueDate.getDate() + (story.estimate || 3));
  const dueDateFormatted = dueDate.toISOString().split('T')[0] + 'T12:00:00.000Z';

  // Build the card description
  const description = [
    `**Role:** ${story.role}`,
    `**Goal:** ${story.goal}`,
    `**Benefit:** ${story.benefit}`,
    `**Estimate:** ${story.estimate} days`,
    `**Priority:** ${story.priority}`,
    `**Tags:** ${(story.tags || []).join(', ')}`,
    `**Dependencies:** ${(story.dependencies || []).join(', ') || 'None'}`
  ].join('\n');

  // Format the card name (e.g., "US-001: User Authentication")
  const cardName = `${story.id}: ${story.title}`;

  return {
    json: {
      // Trello card fields
      idList: story.listId,
      name: cardName,
      desc: description,
      due: dueDateFormatted,
      pos: index + 1,  // position on the list (1-indexed)
      idMembers: story.assigneeIds || [],

      // Additional metadata for downstream nodes (checklists, etc.)
      acceptance_criteria: story.acceptance_criteria || [],
      originalStory: {
        id: story.id,
        title: story.title,
        role: story.role,
        goal: story.goal,
        benefit: story.benefit,
        priority: story.priority,
        estimate: story.estimate,
        sprint: story.sprint
      }
    }
  };
});

return formattedCards;

// Get the created cards from the HTTP request (input to this node)
const createdCards = $input.all();

// Get the original formatted cards (from the Format Cards node)
const formattedCards = $('Format Cards').all();

if (createdCards.length !== formattedCards.length) {
  console.warn(`Mismatch: created ${createdCards.length} cards but expected ${formattedCards.length}`);
}

// Merge each created card with its corresponding original story data
const merged = createdCards.map((cardItem, idx) => {
  const card = cardItem.json;
  const original = formattedCards[idx]?.json || {};

  return {
    json: {
      // Trello card data
      id: card.id,
      idList: card.idList,
      idMembers: card.idMembers,
      name: card.name,
      desc: card.desc,
      due: card.due,
      shortUrl: card.shortUrl,
      url: card.url,

      // Original story metadata (for checklist creation)
      acceptanceCriteria: original.acceptance_criteria || [],
      originalStory: original.originalStory || null
    }
  };
});

return merged;

// Get all merged cards from the previous node
const cards = $input.all();

// Create a checklist request for each card that has acceptance criteria
const requests = [];

for (const cardItem of cards) {
  const card = cardItem.json;
  const cardId = card.id;
  const criteria = card.acceptanceCriteria || card.acceptance_criteria || [];

  if (!criteria.length) {
    console.log(`Card ${cardId} has no acceptance criteria, skipping checklist`);
    continue;
  }

  // Create a request object for the HTTP node
  requests.push({
    json: {
      method: 'POST',
      url: 'https://api.trello.com/1/checklists',
      query: {
        idCard: cardId,
        name: 'Acceptance Criteria'
      },
      // Store the criteria for the next node (Prepare Checklist Items)
      _cardId: cardId,
      _criteria: criteria
    }
  });
}

return requests;

// Get the created checklists (from the "Add Checklist" HTTP node)
const checklists = $input.all();

// Get the original requests (from the "Checklist Request" node)
const originalRequests = $('Checklist Request').all();

// Prepare individual checklist item requests
const items = [];

for (let i = 0; i < checklists.length; i++) {
  const checklist = checklists[i].json;
  const checklistId = checklist.id;

  // Find the matching original request (by position, assuming same order)
  const originalReq = originalRequests[i]?.json;
  const criteria = originalReq?._criteria || [];

  if (!criteria.length) {
    console.log(`Checklist ${checklistId} has no criteria, skipping items`);
    continue;
  }

  // Create one request per acceptance criterion
  criteria.forEach((criterion, idx) => {
    items.push({
      json: {
        method: 'POST',
        url: `https://api.trello.com/1/checklists/${checklistId}/checkItems`,
        query: {
          name: criterion,
          pos: idx  // position on the checklist (0-based)
        }
      }
    });
  });
}

return items;

// Get the stories from the Parse LLM node
const parseLlmOutput = $('Parse LLM').first().json;
const stories = parseLlmOutput.stories || [];

// Get the project from the Get Project node
const project = $('Get Project').first().json;

if (!stories.length) {
  console.log('No stories to update, skipping DB updates');
  return [{ json: { skipped: true, message: 'No stories found' } }];
}

// Extract new story IDs
const newStoryIds = stories.map(s => s.id);
const oldPending = project.us_pending || [];
const newPending = [...oldPending, ...newStoryIds];

// Prepare profile assignments (person_id, effort, project_name)
const assignments = [];
stories.forEach(story => {
  (story.assigned || []).forEach(assignee => {
    assignments.push({
      person_id: assignee.person_id,
      effort: assignee.effort,
      project_name: project.name
    });
  });
});

// Build SQL for updating profiles
let profileSql = '';
for (const a of assignments) {
  profileSql += `
    UPDATE profile 
    SET 
      assigned_effort_points = assigned_effort_points + ${a.effort},
      current_projects = CASE
        WHEN current_projects IS NULL THEN jsonb_build_array('${a.project_name}')
        WHEN current_projects @> jsonb_build_array('${a.project_name}') THEN current_projects
        ELSE current_projects || jsonb_build_array('${a.project_name}')
      END
    WHERE id = ${a.person_id};
  `;
}

return [{
  json: {
    project_id: project.id,
    us_pending: newPending,
    us_done: project.us_done || [],
    assignments: assignments,
    profile_update_sql: profileSql.trim()
  }
}];

// Get the input (already parsed by the router's classifier)
const input = $input.first().json;
const projectName = input.project_name;
const meetingMinutes = input.meeting_minutes;
const reportDate = new Date().toISOString().slice(0, 10);

if (!projectName) throw new Error('project_name is required');
if (!meetingMinutes) throw new Error('meeting_minutes is required');

// Extract blockers from the minutes (simple approach: look for **BLOCKERS** section)
const blockerMatch = meetingMinutes.match(/\*\*BLOCKERS & IMPEDIMENTS\*\*([\s\S]*?)(?=\n\*\*|$)/i);
let blockers = [];
if (blockerMatch) {
  const blockerText = blockerMatch[1];
  // Split by bullet points or newlines
  blockers = blockerText.split(/\n\s*\*\s*/).filter(b => b.trim().length > 0);
}

const prompt = `You are an operations assistant for a Scrum board.

Extract a strict JSON object from the daily standup notes.

INPUTS
Project name: ${projectName}
Report date: ${reportDate}
Meeting minutes:
${meetingMinutes}

Blockers:
${JSON.stringify(blockers, null, 2)}

Return ONLY valid JSON with this exact shape:
{
  "project_name": string,
  "summary": string,
  "completed_tasks": [
    {
      "user_story_id": string | null,
      "user_story_title": string,
      "priority": "Low" | "Medium" | "High",
      "assignee_email": string | null,
      "trello_card_id": string | null,
      "behind_schedule": boolean,
      "current_status": string | null,
      "target_status": "Done",
      "reason": string
    }
  ],
  "notifications": [
    {
      "user_story_id": string | null,
      "user_story_title": string,
      "assignee_email": string | null,
      "priority": "Low" | "Medium" | "High",
      "behind_schedule": true,
      "message": string,
      "reason": string
    }
  ]
}

Rules:
- completed_tasks must include any task explicitly marked done, finished, merged, shipped, or completed in the minutes.
- behind_schedule must be true when the person is blocked, late, waiting on dependency, or missed a due date.
- notifications must include all behind schedule assigned tasks.
- priority should be High for blockers that stop delivery, Medium for normal risk, Low for minor delays.
- Return JSON only. No markdown. No explanation.`;

return [{
  json: {
    project_name: projectName,
    meeting_minutes: meetingMinutes,
    blockers: blockers,
    report_date: reportDate,
    prompt: prompt,
    bodyForOllama: {
      model: "gpt-oss:120b",
      prompt: prompt,
      format: "json",
      stream: false
    }
  }
}];

// Get all input items (cards, lists, and parsed standup data)
const items = $input.all();

// Separate cards, lists, and parsed data
const cards = [];
const lists = [];
let parsedData = null;

for (const item of items) {
  const obj = item.json;
  // Cards have idMembers (array) and no 'closed' (or have idList)
  if (obj.idMembers && Array.isArray(obj.idMembers)) {
    cards.push(obj);
  }
  // Lists have 'name' and 'closed' (or no idMembers)
  else if (obj.name && (obj.closed !== undefined || !obj.idMembers)) {
    lists.push(obj);
  }
  // Parsed standup data has 'project_name' and 'completed_tasks'
  else if (obj.project_name && obj.completed_tasks) {
    parsedData = obj;
  }
}

if (!parsedData) {
  throw new Error('Could not find parsed standup data in input (missing project_name or completed_tasks)');
}

const completedTasks = parsedData.completed_tasks || [];
const notifications = parsedData.notifications || [];
const rawBlockers = parsedData.raw_blockers || [];

// Find the "Done" list
const doneList = lists.find(l => /^done$/i.test(l.name.trim())) ||
                 lists.find(l => /completed?/i.test(l.name.trim())) ||
                 null;

if (!doneList) {
  console.warn('No Done list found; move actions will be skipped');
}

// Helper: extract story ID from card name (e.g., "US-001: Title" or "US-001")
function extractStoryId(cardName) {
  const match = String(cardName || '').match(/^([A-Z]{2,}-\d+)/);
  return match ? match[1] : null;
}

// Helper: match a task to a card
function findCardForTask(task, cards) {
  if (task.trello_card_id) {
    return cards.find(c => c.id === task.trello_card_id);
  }
  if (task.user_story_id) {
    return cards.find(c => extractStoryId(c.name) === task.user_story_id);
  }
  if (task.user_story_title) {
    const lowerTitle = task.user_story_title.toLowerCase();
    return cards.find(c => c.name.toLowerCase().includes(lowerTitle));
  }
  return null;
}

// Prepare move items (cards to move to Done)
const moveItems = [];
for (const task of completedTasks) {
  const card = findCardForTask(task, cards);
  if (!card) continue;
  if (doneList && card.idList !== doneList.id) {
    moveItems.push({
      card_id: card.id,
      done_list_id: doneList.id,
      story_id: extractStoryId(card.name) || task.user_story_id,
      story_title: card.name
    });
  }
}

// Prepare notify items (cards behind schedule)
const notifyItems = [];
for (const note of notifications) {
  const card = findCardForTask(note, cards);
  if (!card) continue;
  const memberIds = card.idMembers || [];
  if (memberIds.length === 0) continue;
  notifyItems.push({
    card_id: card.id,
    story_id: extractStoryId(card.name) || note.user_story_id,
    story_title: card.name,
    member_ids: memberIds,
    priority: note.priority || 'Medium',
    message: note.message || note.reason || 'Task is behind schedule.',
    reason: note.reason || '',
    project_name: parsedData.project_name
  });
}

// Prepare blocker items (from raw_blockers, if any)
const blockerItems = [];
const blockersList = lists.find(l => /^blockers?$/i.test(l.name.trim())) || lists[0];
for (const blockerText of rawBlockers) {
  if (!blockerText || blockerText.trim() === '') continue;
  blockerItems.push({
    title: `Blocker: ${blockerText.substring(0, 100)}`,
    description: `Reported during daily standup.\n\nDetails: ${blockerText}`,
    list_id: blockersList?.id
  });
}

// Build output items for downstream branching
const outputItems = [];
if (moveItems.length > 0) outputItems.push({ json: { type: 'move', items: moveItems } });
if (notifyItems.length > 0) outputItems.push({ json: { type: 'notify', items: notifyItems } });
if (blockerItems.length > 0) outputItems.push({ json: { type: 'create_blocker', items: blockerItems } });

return outputItems;

// Get the LLM response (output from the HTTP Request node)
const llmOutput = $input.first().json;

// Extract raw response text
let rawResponse = '';
if (llmOutput.response) {
  rawResponse = llmOutput.response;
} else if (llmOutput.text) {
  rawResponse = llmOutput.text;
} else if (llmOutput.content) {
  rawResponse = llmOutput.content;
} else if (typeof llmOutput === 'string') {
  rawResponse = llmOutput;
} else if (Array.isArray(llmOutput) && llmOutput[0]?.response) {
  rawResponse = llmOutput[0].response;
} else {
  throw new Error('Could not find response text in LLM output');
}

// Strip markdown code fences if present
let cleaned = rawResponse.trim();
if (cleaned.startsWith('```json')) {
  cleaned = cleaned.replace(/^```json\s*\n?/, '').replace(/\n?```$/, '');
} else if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```\s*\n?/, '').replace(/\n?```$/, '');
}

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error(`Failed to parse JSON: ${err.message}\nRaw: ${cleaned.substring(0, 500)}`);
}

// Extract fields with defaults
const projectName = parsed.project_name || null;
const summary = parsed.summary || '';
const completedTasks = Array.isArray(parsed.completed_tasks) ? parsed.completed_tasks : [];
const notifications = Array.isArray(parsed.notifications) ? parsed.notifications : [];

// Return in the format expected by the rest of the standup workflow
return [{
  json: {
    project_name: projectName,
    summary: summary,
    completed_tasks: completedTasks,
    notifications: notifications,
    raw_blockers: []  // optional, could be extracted from the minutes separately
  }
}];

const input = $input.first().json;

// If the body is a string, parse it
let payload = input;
if (typeof input.body === 'string') {
  try {
    payload = JSON.parse(input.body);
  } catch (e) {
    throw new Error('Failed to parse body as JSON: ' + e.message);
  }
} else if (input.project_name && input.meeting_minutes) {
  // Already parsed
  payload = input;
} else {
  throw new Error('Unable to find project_name and meeting_minutes in input');
}

const minutes = payload.meeting_minutes || '';
const isStandup = minutes.includes('STANDUP OVERVIEW');

return [{
  json: {
    ...payload,
    meeting_type: isStandup ? 'standup' : 'new_project'
  }
}];

// Get the first input item (or use the whole array)
const items = $input.all();
let inputData = items[0]?.json || {};

// If the input itself is an array of notifications (common after IF)
if (Array.isArray(inputData) && inputData.length) {
  inputData = { items: inputData };
}
// If the input has no 'items' but directly contains notification fields
if (!inputData.items && inputData.card_id) {
  inputData = { items: [inputData] };
}

const notifications = inputData.items || [];

const emailItems = [];

for (const note of notifications) {
  const memberIds = note.member_ids || [];
  for (const memberId of memberIds) {
    emailItems.push({
      json: {
        member_id: memberId,
        card_id: note.card_id,
        story_id: note.story_id,
        story_title: note.story_title,
        priority: note.priority,
        message: note.message,
        reason: note.reason,
        project_name: note.project_name
      }
    });
  }
}

// If still no items, return a dummy to avoid workflow hanging
if (emailItems.length === 0) {
  console.warn('No email items generated – skipping');
  return [{ json: { skipped: true, reason: 'no members or notifications' } }];
}

return emailItems;
